-- ----------------------------
-- Table structure for classify
-- ----------------------------
DROP TABLE IF EXISTS `classify`;
CREATE TABLE `classify` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '分类id',
  `fid` int NOT NULL DEFAULT '0' COMMENT '分类父id',
  `name` varchar(80) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '分类名称',
  `pinyin` varchar(80) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '分类拼音',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '默认状态1启用，0关闭',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序',
  `type` int DEFAULT NULL COMMENT '分类类型\n默认值为null，即公用分类，\n1：漫画分类',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb3 COMMENT='分类表\ntype: 代表一个分类比如1代表漫画';

-- ----------------------------
-- Records of classify
-- ----------------------------
BEGIN;
COMMIT;

