-- ----------------------------
-- Table structure for mantra
-- ----------------------------
DROP TABLE IF EXISTS `mantra`;
CREATE TABLE `mantra` (
  `id` int NOT NULL AUTO_INCREMENT,
  `type` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '产品类型',
  `uid` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '添加用户id，空为系统添加',
  `title` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '标题',
  `show_title` int NOT NULL DEFAULT '1' COMMENT '是否显示标题：1显示（默认），0不显示',
  `content` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '内容',
  `isplus` int DEFAULT '1' COMMENT '是否会员使用：1会员可用，0普通用户可用',
  `font_size` int DEFAULT NULL COMMENT '字体大小',
  `font_family` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '字体',
  `pay_type` int DEFAULT '11' COMMENT '支付类型，详见product_pay_type，1为皮肤themes, 2为声音sounds，3为颜色colors，10为单独产品支付，11为VIP',
  `price` int NOT NULL DEFAULT '0' COMMENT '价格',
  `status` int DEFAULT '1' COMMENT '上架状态：1默认上架；0下架',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=75 DEFAULT CHARSET=utf8mb3;

