-- ----------------------------
-- Table structure for product
-- ----------------------------
DROP TABLE IF EXISTS `product`;
CREATE TABLE `product` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `pro_id` int NOT NULL COMMENT '产品分类id',
  `uid` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '上传用户UID',
  `type` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '分组类型：theme为皮肤, sound为声音，color为颜色，空在输出时将做为children列表输出',
  `name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '名称',
  `describe` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '描述',
  `icon` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '图标',
  `color` varchar(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '颜色',
  `thumb` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '缩略图',
  `src` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '图片路径',
  `background` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '背景图片',
  `url` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '跳转地址',
  `deep` int DEFAULT NULL COMMENT '一炷香中香坛坛口深度；\n木鱼在页面的位置',
  `pay_type` int DEFAULT NULL COMMENT '支付类型，详见product_pay_type，1为皮肤themes, 2为声音sounds，3为颜色colors，10为单独产品支付，11为VIP',
  `price` int NOT NULL DEFAULT '0' COMMENT '原价格',
  `discount` int NOT NULL DEFAULT '0' COMMENT '折扣价',
  `knock_txt` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '当前产品默认敲击文本',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序',
  `status` int NOT NULL DEFAULT '1' COMMENT '是否启用，默认为1（启用）,0不启用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=102 DEFAULT CHARSET=utf8mb3;

-- ----------------------------
-- Records of product
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for product_classify
-- ----------------------------
DROP TABLE IF EXISTS `product_classify`;
CREATE TABLE `product_classify` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `fid` int DEFAULT NULL COMMENT '父ID',
  `name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '名称',
  `describe` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '描述',
  `type` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '类型',
  `icon` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '图标',
  `knock_txt` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '敲击文本',
  `mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT '自动模式',
  `interval_time` int NOT NULL DEFAULT '10' COMMENT '间隔时长',
  `interval_min` int NOT NULL DEFAULT '3' COMMENT '最新间隔时长',
  `interval_max` int NOT NULL DEFAULT '30' COMMENT '最大间隔时长',
  `timing` int NOT NULL DEFAULT '20' COMMENT '定时时间',
  `timing_min` int NOT NULL DEFAULT '10' COMMENT '最小定时时间',
  `timing_max` int NOT NULL DEFAULT '120' COMMENT '最大定时时间',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否启用',
  `ismenu` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否开启菜单\n1：默认开启\n0：不是菜单',
  `istab` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为tab菜单\n1：是tab\n0：默认不是tab',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb3;

-- ----------------------------
-- Records of product_classify
-- ----------------------------
BEGIN;
COMMIT;

