DROP TABLE IF EXISTS `product_pay_type`;
CREATE TABLE `product_pay_type` (
  `id` int NOT NULL AUTO_INCREMENT,
  `fid` int DEFAULT NULL COMMENT '父ID',
  `key` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '健值',
  `name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '名字',
  `power` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '支付此类型产品的权限\n年:y,季度:Q;几个月:M;周:w;天:d;小时:h;分钟:m;秒:s;毫秒:ms',
  `plus` int NOT NULL COMMENT '支付此类型产品的权限值',
  `welfare` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '支付此类型产品描述',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '启用状态: 1启用（默认）；0禁用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
